"use client";

import { Timer as ArkTimer } from "@ark-ui/react/timer";
import type React from "react";
import { cn } from "@/lib/utils";

const timerRootClass = cn("flex flex-col items-start gap-4 text-foreground");

const timerAreaClass = cn("flex items-center gap-2");

const timerItemGroupClass = cn("flex flex-col items-center gap-0");

const timerItemClass = cn(
  "min-w-[2ch] text-center font-semibold text-2xl text-foreground tabular-nums"
);

const timerItemLabelClass = cn("text-muted-foreground text-xs");

const timerSeparatorClass = cn("font-semibold text-2xl text-muted-foreground");

const timerControlClass = cn("flex items-center gap-2");

const timerActionTriggerClass = cn(
  "inline-flex cursor-pointer items-center justify-center gap-2 rounded-md border border-input bg-transparent px-4 py-2 font-medium text-foreground text-sm transition-colors",
  "hover:bg-muted",
  "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
  "data-disabled:opacity-50 data-disabled:grayscale",
  "[&_svg]:size-4"
);

interface TimerRootProps extends React.ComponentProps<typeof ArkTimer.Root> {
  className?: string;
}

const TimerRoot = (props: TimerRootProps) => {
  const { className, ...rest } = props;
  return (
    <ArkTimer.Root
      className={cn(timerRootClass, className)}
      data-slot="timer"
      {...rest}
    />
  );
};

const TimerArea = (props: React.ComponentProps<typeof ArkTimer.Area>) => (
  <ArkTimer.Area
    className={cn(timerAreaClass, props.className)}
    data-slot="timer-area"
    {...props}
  />
);

const TimerItem = (props: React.ComponentProps<typeof ArkTimer.Item>) => (
  <ArkTimer.Item
    className={cn(timerItemClass, props.className)}
    data-slot="timer-item"
    {...props}
  />
);

const TimerSeparator = (
  props: React.ComponentProps<typeof ArkTimer.Separator>
) => (
  <ArkTimer.Separator
    className={cn(timerSeparatorClass, props.className)}
    {...props}
  />
);

const TimerControl = (props: React.ComponentProps<typeof ArkTimer.Control>) => (
  <ArkTimer.Control
    className={cn(timerControlClass, props.className)}
    data-slot="timer-control"
    {...props}
  />
);

const TimerActionTrigger = (
  props: React.ComponentProps<typeof ArkTimer.ActionTrigger>
) => (
  <ArkTimer.ActionTrigger
    className={cn(timerActionTriggerClass, props.className)}
    data-slot="timer-action"
    {...props}
  />
);

export const Timer = {
  Root: TimerRoot,
  Area: TimerArea,
  Item: TimerItem,
  Separator: TimerSeparator,
  Control: TimerControl,
  ActionTrigger: TimerActionTrigger,
};
